options.content:
{{#if (eq UserIsAdmin 0)}}
  <div style="color: #e02424; background: rgba(224, 36, 36, 0.05); border-left: 4px solid #e02424; padding: 8px 14px; font-size: 13px; display: flex; align-items: center; gap: 8px; border-radius: 2px; line-height: 1.4;">
    <span>⚠️</span>
    <span><strong>Access Denied:</strong> You must be a admin to view this page.</span>
  </div>
{{/if}}

options.afterRender:
var el = context.element || context.grafana?.element;
if (!el) return;
var root = el.querySelector('#h3-root');
if (!root) return;
var s = root.dataset.status;
var cfg = {
  success:{bg:'#f0fdf4',bd:'#bbf7d0',ib:'#dcfce7',clr:'#16a34a',lbl:'All Good',sub:'All systems operational',svg:'<polyline points="8 12 11 15 16 9"/>'},
  failed:{bg:'#fef2f2',bd:'#fecaca',ib:'#fee2e2',clr:'#dc2626',lbl:'Failed',sub:'Check error details below',svg:'<line x1="15" y1="9" x2="9" y2="15"/><line x1="9" y1="9" x2="15" y2="15"/>'},
  in_progress:{bg:'#fffbeb',bd:'#fde68a',ib:'#fef3c7',clr:'#d97706',lbl:'Refreshing\u2026',sub:'Refresh in progress',svg:'<polyline points="12 6 12 12 16 14"/>'},
  queued:{bg:'#fffbeb',bd:'#fde68a',ib:'#fef3c7',clr:'#d97706',lbl:'Queued',sub:'Refresh queued, waiting to start',svg:'<polyline points="12 6 12 12 16 14"/>'}
};
var c = cfg[s] || {bg:'#eff6ff',bd:'#bfdbfe',ib:'#dbeafe',clr:'#2563eb',lbl:'Idle',sub:'Waiting for first run',svg:'<polyline points="12 6 12 12 16 14"/>'};
var card = el.querySelector('#h3-st-card');
card.style.background = c.bg;
card.style.border = '1px solid ' + c.bd;
var icon = el.querySelector('#h3-st-icon');
icon.style.background = c.ib;
icon.innerHTML = '<svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="'+c.clr+'" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/>'+c.svg+'</svg>';
var lbl = el.querySelector('#h3-st-label');
lbl.style.color = c.clr;
lbl.textContent = c.lbl;
el.querySelector('#h3-st-sub').textContent = c.sub;
var ms = Number(root.dataset.ms);
if (ms) {
  var d = new Date(ms);
  var months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  el.querySelector('#h3-date').textContent = months[d.getMonth()] + ' ' + d.getDate() + ', ' + d.getFullYear();
  el.querySelector('#h3-time').textContent = d.toLocaleTimeString('en-GB',{hour12:false});
}

var el = context.element || context.grafana?.element;
if (!el) return;
var btn = el.querySelector('#h360-refresh-btn');
if (btn && !btn.disabled) {
  btn.onclick = async function() {
    if (!confirm('This will refresh all reporting materialized views. The refresh runs in the background and may take a few minutes. Continue?')) return;
    this.disabled = true;
    this.innerHTML = '<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="animation:h360spin 1s linear infinite"><path d="M21 12a9 9 0 1 1-6.219-8.56"/></svg> Refresh in queue\u2026';
    this.style.background = '#d97706';
    this.style.cursor = 'not-allowed';
    try {
      await fetch('/api/ds/query', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ queries: [{ refId: 'A', datasource: { uid: 'postgres-grafana', type: 'grafana-postgresql-datasource' }, rawSql: "SELECT heart360tk_reporting.start_async_refresh('manual') AS result", format: 'table', rawQuery: true }], from: '0', to: '0' })
      });
    } catch(e) {
      this.disabled = false;
      this.innerHTML = '\u27f3 Refresh Dashboard';
      this.style.background = '#1f62e0';
      this.style.cursor = 'pointer';
      alert('Failed to trigger refresh. Please try again.');
    }
  };
}

list.definition:
SELECT CASE WHEN (u.is_admin OR EXISTS (
  SELECT 1 FROM team_member tm
  JOIN team t ON tm.team_id = t.id
  WHERE tm.user_id = u.id AND t.name LIKE '%\_ALL' ESCAPE '\'
)) THEN 1 ELSE 0 END
FROM "user" u WHERE u.id = ${__user.id}

